        // 1. Run schema migrations
        Liquibase schemaLiquibase = new Liquibase("migration/schema/modernization_schema.xml", new ClassLoaderResourceAccessor(), database);
        schemaLiquibase.update("");
        
        // Ensure new table exists
        java.sql.ResultSet rs = conn.createStatement().executeQuery("SELECT count(*) FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME = 'CRF_LOCK_REGISTRY'");
        rs.next();
        assertEquals("Table should exist after update", 1, rs.getInt(1));

        // Validate it rolled back
        try {
            schemaLiquibase.rollback(150, "");
        } catch (Exception e) {
            fail("Schema migration rollback failed: " + e.getMessage());
        }
        
        // Schema Comparison Check: Ensure the post-rollback schema matches the baseline schema
        rs = conn.createStatement().executeQuery("SELECT count(*) FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME = 'CRF_LOCK_REGISTRY'");
        rs.next();
        assertEquals("Schema comparison check: table should be removed after rollback matching baseline", 0, rs.getInt(1));

        // Apply it again so data migration has schemas if needed
        schemaLiquibase.update("");

        // 2. Run data migrations and verify rollback fails due to irreversible changes
        Liquibase dataLiquibase = new Liquibase("migration/data/modernization_data.xml", new ClassLoaderResourceAccessor(), database);
        dataLiquibase.update("");
        
        try {
            dataLiquibase.rollback(5, "");
            fail("Expected RollbackImpossibleException was not thrown for data migration.");
        } catch (Exception e) {
            String stackTrace = "";
            for (Throwable t = e; t != null; t = t.getCause()) {
                stackTrace += t.getClass().getName() + ": " + t.getMessage() + "\n";
            }
            assertTrue("Expected RollbackImpossibleException or RollbackFailedException", stackTrace.contains("RollbackImpossibleException") || stackTrace.contains("Rollback is not supported") || stackTrace.contains("Automated rollback: Data/schema changes must be manually reviewed if destructive."));
        }
